#include <iostream>
#include <algorithm>
#include <cmath>
#include <iomanip>
#include <vector>

using namespace std;

const int N = 1010;
const int M = N * N;

int f[N];

int find(int x) {
    return x == f[x] ? x : f[x] = find(f[x]);
}

void merge(int x, int y) {
    f[find(x)] = find(y);
}

struct E {
    int u, v;
    double w;
}e[M];

bool cmp(E x, E y) {
    return x.w < y.w;
}

struct P {
    int x, y;
}p[N];

double dis(P a, P b) {
    return sqrt((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y));
}

int main() {
    int n, k;
    cin >> n >> k;
    for (int i = 0; i < n; i++) {
        cin >> p[i].x >> p[i].y;
    }
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double d = dis(p[i], p[j]);
            e[cnt].u = i;
            e[cnt].v = j;
            e[cnt].w = d;
            cnt++;
        }
    }
    sort(e, e + cnt, cmp);
    for (int i = 0; i < n; i++) {
        f[i] = i;
    }
    vector<double> edges;
    for (int i = 0; i < cnt; i++) {
        if (find(e[i].u) != find(e[i].v)) {
            merge(e[i].u, e[i].v);
            edges.push_back(e[i].w);
        }
    }
    double ans = edges[n - k];
    printf("%.2lf", ans);
    return 0;
}
